#include <stdio.h>
#include <cuda.h>

struct Node
{
    int starting;
    int no_of_edges;
};

__global__ void bfs_first_kernel(Node* d_graph_nodes, bool* d_graph_mask, bool* d_graph_visited, 
                                  int* d_graph_edges, int* d_cost, bool* d_updating_graph_mask, int no_of_nodes)
{
    int x_12 = threadIdx.x + blockIdx.x * blockDim.x;

    if(x_12 < no_of_nodes)
    {
        if(d_graph_mask[x_12] == true)
        { 
            d_graph_mask[x_12] = false;
            for(int i = d_graph_nodes[x_12].starting; 
                i < (d_graph_nodes[x_12].no_of_edges + d_graph_nodes[x_12].starting); i++)
            {
                int x_3 = d_graph_edges[i];
                if(!d_graph_visited[x_3])
                {
                    d_cost[x_3] = d_cost[x_12] + 1;
                    d_updating_graph_mask[x_3] = true;
                }
            }
        }
    }
}

